// src/components/layouts/UserLayout.jsx
import React, { useState } from "react";

// Import the new UserDashboard component
import UserDashboard from "../pa/UserDashboard";

/*
  UserLayout.jsx
  -------------------------
  Simple, friendly layout for non-technical users.
  - Permanent shell (header, nav, main, footer)
  - Child pages rendered inside via internal state (no router)
  - Minimal UI, clear language, no technical jargon
  - Dummy data only (replace with APIs later)
  - Tailwind CSS utility classes used for styling
*/

/* --------------------------
   My System Page
   -------------------------- */
function MySystemPage() {
  return (
    <div className="space-y-6">
      {/* Page Header */}
      <div>
        <h2 className="text-2xl font-semibold text-slate-900 mb-2">My System</h2>
        <p className="text-sm text-slate-600 max-w-2xl">
          View a friendly summary of your assigned device. If something feels wrong, 
          request support — we'll take it from there.
        </p>
      </div>

      {/* System Details Card */}
      <div className="bg-white border border-gray-200 rounded-lg p-6">
        <div className="flex flex-col sm:flex-row items-start gap-6">
          {/* System Icon */}
          <div className="w-24 h-24 rounded-lg bg-gradient-to-br from-blue-50 to-blue-100 border border-blue-200 flex items-center justify-center text-2xl font-bold text-blue-700 flex-shrink-0">
            SYS
          </div>
          
          {/* System Info */}
          <div className="flex-1 space-y-4">
            {/* System ID */}
            <div>
              <div className="text-xs font-medium text-slate-500 uppercase tracking-wide">
                System ID
              </div>
              <div className="font-semibold text-lg text-slate-900 mt-1">SYS-8472</div>
            </div>

            {/* Status */}
            <div>
              <div className="text-xs font-medium text-slate-500 uppercase tracking-wide">
                Status
              </div>
              <div className="flex items-center gap-3 mt-1">
                <span className="inline-flex items-center px-3 py-1 rounded-full bg-green-100 text-green-700 text-sm font-medium border border-green-200">
                  ✓ Healthy
                </span>
                <span className="text-sm text-slate-600">Confidence: <strong>92%</strong></span>
              </div>
            </div>

            {/* Owner */}
            <div>
              <div className="text-xs font-medium text-slate-500 uppercase tracking-wide">
                Owner
              </div>
              <div className="text-sm text-slate-700 mt-1">Manufacturing Department / Line B</div>
            </div>
          </div>
        </div>
      </div>

      {/* Monitoring Info Card */}
      <div className="bg-blue-50 border border-blue-200 rounded-lg p-6">
        <h3 className="text-base font-semibold text-slate-900 mb-3 flex items-center gap-2">
          <span className="text-lg">🔍</span> What we monitor
        </h3>
        <p className="text-sm text-slate-700 leading-relaxed">
          We continuously check your device for anything that affects reliability and performance. 
          This view shows only outcomes (<strong>healthy</strong> / <strong>needs attention</strong>) 
          — no technical metrics are shown here. Our AI monitors hardware health, software status, 
          and security indicators automatically.
        </p>
      </div>

      {/* Quick Actions */}
      <div className="bg-white border border-gray-200 rounded-lg p-6">
        <h3 className="text-base font-semibold text-slate-900 mb-4">Quick Actions</h3>
        <div className="flex flex-col sm:flex-row gap-3">
          <button className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors">
            Request Support
          </button>
          <button className="px-4 py-2 border border-gray-300 text-slate-700 rounded-lg text-sm font-medium hover:bg-gray-50 transition-colors">
            View History
          </button>
        </div>
      </div>
    </div>
  );
}

/* --------------------------
   Support Request Page
   -------------------------- */
function SupportRequestPage({ user }) {
  const [message, setMessage] = useState("");
  const [submitted, setSubmitted] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState("");

  const submit = (e) => {
    e.preventDefault();
    setError("");
    
    // Validation
    if (!message.trim()) {
      setError("Please describe the issue before submitting.");
      return;
    }
    
    if (message.trim().length < 10) {
      setError("Please provide more details (at least 10 characters) so we can help you better.");
      return;
    }

    // Simulate submission with loading state
    setIsSubmitting(true);
    
    setTimeout(() => {
      console.log("Support request submitted:", { from: user.email, message });
      setIsSubmitting(false);
      setSubmitted(true);
    }, 1000);
  };

  const reset = () => {
    setMessage("");
    setSubmitted(false);
    setError("");
  };

  return (
    <div className="max-w-2xl space-y-6">
      {/* Page Header */}
      <div>
        <h2 className="text-2xl font-semibold text-slate-900 mb-2">Support Request</h2>
        <p className="text-sm text-slate-600">
          Tell us what's wrong in plain language. Include photos or additional details if available.
        </p>
      </div>

      {!submitted ? (
        <div className="bg-white border border-gray-200 rounded-lg p-6">
          <div className="space-y-5">
            {/* Form Instructions */}
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
              <h4 className="text-sm font-semibold text-slate-900 mb-2">💡 Tips for a quick response:</h4>
              <ul className="text-sm text-slate-700 space-y-1">
                <li>• Describe what happened in your own words</li>
                <li>• Mention the system ID if you know it (e.g., SYS-8472)</li>
                <li>• Attach photos if the issue is visible</li>
              </ul>
            </div>

            {/* Form */}
            <div className="space-y-4">
              <label className="block">
                <div className="text-sm font-medium text-slate-700 mb-2">
                  Describe the problem <span className="text-red-500">*</span>
                </div>
                <textarea
                  value={message}
                  onChange={(e) => {
                    setMessage(e.target.value);
                    setError("");
                  }}
                  placeholder="Example: The machine on Line B stopped suddenly and shows a red blinking light. I heard an unusual beeping sound before it stopped."
                  className="w-full p-3 border border-gray-300 rounded-lg bg-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all resize-none"
                  rows={8}
                  disabled={isSubmitting}
                />
                <div className="flex justify-between items-center mt-2">
                  <span className="text-xs text-slate-500">
                    {message.length} characters (minimum 10)
                  </span>
                  {message.length >= 10 && (
                    <span className="text-xs text-green-600 font-medium">✓ Good length</span>
                  )}
                </div>
              </label>

              {error && (
                <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg text-sm flex items-start gap-2">
                  <span className="text-red-500">⚠️</span>
                  <span>{error}</span>
                </div>
              )}

              <div className="flex items-center gap-3 pt-2">
                <button 
                  onClick={submit}
                  disabled={isSubmitting}
                  className="px-6 py-2.5 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 disabled:bg-blue-400 disabled:cursor-not-allowed transition-colors"
                >
                  {isSubmitting ? "Submitting..." : "Submit Request"}
                </button>
                <button 
                  type="button" 
                  onClick={() => setMessage("")}
                  disabled={isSubmitting}
                  className="px-4 py-2.5 border border-gray-300 text-slate-700 rounded-lg text-sm font-medium hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-gray-500 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                  Clear
                </button>
              </div>
            </div>
          </div>
        </div>
      ) : (
        // Success State
        <div className="bg-white border border-gray-200 rounded-lg p-8 text-center">
          <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <span className="text-3xl">✓</span>
          </div>
          <h3 className="text-lg font-semibold text-slate-900 mb-2">Request Submitted Successfully!</h3>
          <p className="text-sm text-slate-600 mb-6">
            Thanks — your request has been submitted. A technician will review it and contact you shortly.
          </p>
          <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 mb-6 text-left">
            <div className="text-xs font-medium text-slate-500 mb-1">YOUR MESSAGE:</div>
            <div className="text-sm text-slate-700 italic">"{message}"</div>
          </div>
          <button 
            onClick={reset}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors"
          >
            Submit Another Request
          </button>
        </div>
      )}
    </div>
  );
}

/* ---------------------------------------
   Main UserLayout component (export default)
   --------------------------------------- */
export default function UserLayout({ userData, onLogout }) {
  // Navigation state: local state to switch pages without routing
  const [active, setActive] = useState("dashboard");

  // Use userData from props (passed from App.jsx)
  const user = {
    firstName: userData?.email?.split('@')[0] || "User",
    lastName: "",
    email: userData?.email || "user@example.com",
    avatar: userData?.email?.[0].toUpperCase() || "U",
  };

  // Simple nav items
  const nav = [
    { id: "dashboard", label: "Dashboard", icon: "📊" },
    { id: "mysystem", label: "My System", icon: "💻" },
    { id: "support", label: "Support Request", icon: "💬" },
  ];

  // Render selected child page
  const renderContent = () => {
    switch (active) {
      case "dashboard":
        // Use the new UserDashboard component
        return <UserDashboard user={user} onNavigate={setActive} />;
      case "mysystem":
        return <MySystemPage />;
      case "support":
        return <SupportRequestPage user={user} />;
      default:
        return <UserDashboard user={user} onNavigate={setActive} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16 gap-4">
            {/* Logo Section */}
            <div className="flex items-center gap-3 flex-shrink-0">
              <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-blue-600 to-sky-500 flex items-center justify-center text-white font-bold shadow-sm">
                M
              </div>
              <div className="hidden sm:block">
                <div className="text-base font-semibold text-slate-900">MaintenanceAI</div>
                <div className="text-xs text-slate-500">Employee Portal</div>
              </div>
            </div>

            {/* User Info */}
            <div className="flex items-center gap-3">
              <div className="hidden md:block text-sm text-slate-600">
                Signed in as <strong>{user.firstName}</strong>
              </div>

              <div className="flex items-center gap-2 bg-gray-50 border border-gray-200 rounded-lg px-3 py-2">
                <div className="w-8 h-8 rounded-full bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center text-xs font-semibold text-white">
                  {user.avatar}
                </div>
                <div className="hidden sm:block text-sm text-slate-700 max-w-[150px] truncate">
                  {user.email}
                </div>
              </div>

              {/* Logout Button */}
              <button
                onClick={onLogout}
                className="px-3 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg border border-red-200 font-medium transition-colors"
              >
                Logout
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Secondary nav */}
      <nav className="bg-white border-b sticky top-0 z-10 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center h-12 gap-2 sm:gap-6 overflow-x-auto">
            {nav.map((n) => (
              <button
                key={n.id}
                onClick={() => setActive(n.id)}
                className={`text-sm px-3 py-2 whitespace-nowrap border-b-2 transition-colors flex items-center gap-2 ${
                  active === n.id
                    ? "border-blue-600 text-blue-700 font-medium bg-blue-50"
                    : "border-transparent text-slate-600 hover:text-slate-900 hover:bg-gray-50"
                }`}
              >
                <span className="text-base">{n.icon}</span>
                <span>{n.label}</span>
              </button>
            ))}
          </div>
        </div>
      </nav>

      {/* Main content area */}
      <main className="flex-1 overflow-y-auto">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
          {renderContent()}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t mt-auto">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 text-sm">
            {/* Support Info */}
            <div>
              <div className="font-semibold text-slate-900 mb-1">Need help?</div>
              <div className="text-slate-600">
                <span className="block sm:inline">
                  Contact support:{" "}
                  <a className="text-blue-600 hover:text-blue-700 hover:underline" href="mailto:support@company.com">
                    support@company.com
                  </a>
                </span>
                <span className="hidden sm:inline"> • </span>
                <span className="block sm:inline">
                  <a className="text-blue-600 hover:text-blue-700 hover:underline" href="tel:+18005550199">
                    +1 (800) 555-0199
                  </a>
                </span>
              </div>
            </div>

            {/* Copyright */}
            <div className="text-slate-500 text-right">
              <div>© {new Date().getFullYear()} MaintenanceAI</div>
              <div className="text-xs mt-1">Platform v1.0 • Employee Portal</div>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
}
